import { createSlice } from '@reduxjs/toolkit'


export const productListSlice = createSlice({
    name: 'productList',
    initialState: {products: []},
    reducers: {
        productListRequest: (state) => { state.loading = true },
        // productListSuccess: (state, action) => ({ loading: false, product: action.payload }),
        // productListFail: (state, action) => ({ loading: false, error: action.payload }),
    }
})

// export const { productListRequest, productListSuccess, productListFail } = productListSlice.actions
export const { productListRequest } = productListSlice.actions

export default productListSlice.reducer;
